module top_module(clk, rst, en, data_in, data_out);parameter SIZE = 32;
	input clk, rst, en;
	input [SIZE-1:0] data_in;
	output reg [SIZE-1:0] data_out;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk, posedge rst or posedge dbg_halt) begin
		if(rst)
			data_out <= 0;
		else if(en)
			data_out <= data_in;
	end
endmodule
